Bash(node -e "
// For each comet, find closest point on path to origin \(sun at 0,0\)
const comets = [
  { label:'inner', sx:-50, sz:-22, ex:46, ez:26 },
  { label:'outer', sx:-78, sz:-36, ex:68, ez:52 },
];
for \(const c of comets\) {
  const dx = c.ex - c.sx, dz = c.ez - c.sz;
  const len2 = dx*dx + dz*dz;
  const t = Math.max\(0, Math.min\(1, \(\(-c.sx\)*dx + \(-c.sz\)*dz\) / len2\)\);
  const cx = c.sx + dx*t, cz = c.sz + dz*t;
  const dist = Math.sqrt\(cx*cx + cz*cz\);
  console.log\(c.label, '→ closest to sun:', dist.toFixed\(2\), 'at', cx.toFixed\(1\), cz.toFixed\(1\), '\(t='+t.toFixed\(3\)+'\)'\);
}
")

