// Verify new paths are within camera view and safe from sun
// Camera zoom=14, typical 1920x1080 → visible ≈ ±68 X, ±38 Z
// Orbit 4: a=34.5, b=22.5.  Ecosystem zone: a=43.5, b=31.5

function check\(label, sx, sz, ex, ez\) {
  const dx=ex-sx, dz=ez-sz, len2=dx*dx+dz*dz;
  const t=Math.max\(0,Math.min\(1,\(\(-sx\)*dx+\(-sz\)*dz\)/len2\)\);
  const cx=sx+dx*t, cz=sz+dz*t;
  const distSun=Math.sqrt\(cx*cx+cz*cz\);
  function outsideEco\(x,z\){ return x*x/43.5**2+z*z/31.5**2 >= 1; }
  function outsideOrb4\(x,z\){ return x*x/34.5**2+z*z/22.5**2 >= 1; }
  console.log\(label\);
  console.log\('  start',sx,sz,'r='+Math.sqrt\(sx*sx+sz*sz\).toFixed\(1\),'outside-eco:'+outsideEco\(sx,sz\)\);
  console.log\('  end  ',ex,ez,'r='+Math.sqrt\(ex*ex+ez*ez\).toFixed\(1\),'outside-eco:'+outsideEco\(ex,ez\)\);
  console.log\('  closest to sun:',distSun.toFixed\(2\),'at \('+cx.toFixed\(1\)+','+cz.toFixed\(1\)+'\)'\);
  console.log\('  X range:',[sx,ex].map\(v=>v.toFixed\(0\)\),'Z range:',[sz,ez].map\(v=>v.toFixed\(0\)\)\);
}

// Inner: grazes middle orbits, stays outside orbit-1+2
check\('inner', -46, 22, 40, 16\);
// Outer: stays outside all orbits including ecosystem zone
check\('outer', -44, 36, 40, 32\);
